A debounce function delays invoking a function until after a specified pause in calls, preventing it from running too frequently.

```js
// Small debounce
function debounce(fn, wait = 200) {
  let t;
  return function (...args) {
    const ctx = this;
    clearTimeout(t);
    t = setTimeout(() => fn.apply(ctx, args), wait);
  };
}

// Example: run at most after user stops resizing for 250ms
window.addEventListener('resize', debounce(() => {
  console.log('Recalculate layout...');
}, 250));

// Another example: debounce input handler
const input = document.querySelector('#search');
input.addEventListener('input', debounce(function () {
  console.log('Searching for:', this.value);
}, 300));
```
